1:ac0|[package]
2:07c|name = "chat_cli"
3:b22|version.workspace = true
4:327|edition.workspace = true
5:548|authors.workspace = true
6:d05|
7:de8|[dependencies]
8:99f|net_crackpipe = { path = "../../rust_pkg/net_crackpipe" }
9:6d2|game_logic = { path = "../game_logic" }
10:f86|tokio = { version = "1", default-features = false, features = ["rt-multi-thread", "macros", "sync", "io-std", "io-util", "time"] }
11:25d|anyhow = { workspace = true }
12:9cb|tracing-subscriber = { version = "0.3", features = ["env-filter"] }
13:030|futures = "0.3"
14:d05|
15:d8b|[lints]
16:7ac|workspace = true

1:1e8|use anyhow::Context;
2:452|use net_crackpipe::{
3:4c6|    chat::chat_controller::{IChatController, IChatReceiver, IChatSender},
4:f5a|    chat::global_chat::{GlobalChatMessageContent, GlobalChatPresence},
5:f72|    network_manager::NetworkManager,
6:2f9|    user_identity::UserIdentitySecrets,
7:aa9|};
