9:6b0|use tokio::io::{AsyncBufReadExt, BufReader};
10:d05|
11:6dc|#[tokio::main]
12:182|async fn main() -> anyhow::Result<()> {
13:0a6|    // init tracing_subscriber from RUST_LOG (default info)
14:f73|    tracing_subscriber::fmt()
15:156|        .with_env_filter(
16:53a|            tracing_subscriber::EnvFilter::try_from_default_env()
17:7df|                .unwrap_or_else(|_| tracing_subscriber::EnvFilter::new("info")),
18:f8e|        )
19:b85|        .init();
20:d05|
21:da9|    let secrets = UserIdentitySecrets::generate();
22:139|    let own_nickname = secrets.user_identity().nickname();
23:af2|    println!("SELF {}", own_nickname);
24:d05|
25:e91|    // If this process wins a bootstrap slot, its bootstrap node should also
26:113|    // carry the game's extra topics, so use the game network config.
27:60b|    let network = NetworkManager::init(
28:f7a|        Arc::new(secrets),
29:0d8|        game_logic::network::network_manager_config(),
30:f8e|    )
31:dcc|    .await
32:943|    .context("Failed to initialize NetworkManager")?;
33:d05|
34:883|    let controller = network
35:b63|        .global_chat_controller()
36:dcc|        .await
37:36f|        .context("Failed to get global chat controller")?;
38:d05|
39:794|    let sender = controller.sender();
40:d28|    sender
41:ad9|        .set_presence(&GlobalChatPresence {
42:0b5|            url: "".into(),
43:f6b|            platform: "chat_cli".into(),
44:e2b|            is_server: None,
45:417|        })
46:d19|        .await;
47:d05|
48:8f1|    controller
49:805|        .wait_joined(2)
50:dcc|        .await
51:c40|        .context("Failed wait_joined")?;
52:d05|
53:37f|    println!("READY {}", own_nickname);
54:d05|
55:b34|    // Spawn a stdin reader task
56:da4|    let sender_clone = sender.clone();
57:849|    tokio::spawn(async move {
58:197|        let stdin = tokio::io::stdin();
59:b77|        let mut reader = BufReader::new(stdin).lines();
60:e9a|        while let Ok(Some(line)) = reader.next_line().await {
61:4f3|            let trimmed = line.trim();
62:d98|            if !trimmed.is_empty() {
63:9b7|                let msg = GlobalChatMessageContent::TextMessage {
64:085|                    text: trimmed.to_string(),
65:aa9|                };
