67:d7a|                    Ok(_) => {
68:d75|                        println!("SENT {}", trimmed);
69:b18|                    }
70:ba5|                    Err(e) => {
71:cf6|                        eprintln!("Error sending message: {:?}", e);
72:b18|                    }
73:b18|                }
74:b18|            }
75:b18|        }
76:d86|    });
77:d05|
78:aee|    // Main receive loop
79:5d9|    let recv = controller.receiver().await;
80:bab|    while let Some(msg) = recv.next_message().await {
81:46d|        let nickname = msg.from.nickname();
82:698|        match msg.message {
83:643|            GlobalChatMessageContent::TextMessage { text } => {
84:aad|                println!("RECV {} {}", nickname, text);
85:b18|            }
86:ea8|            _ => {}
87:b18|        }
88:b18|    }
89:d05|
90:428|    network.shutdown().await?;
91:8d4|    Ok(())
92:b18|}
93:d05|
94:fb2|#[cfg(test)]
95:2c2|mod tests {
96:e11|    #[test]
97:02e|    fn network_manager_config_builds_with_gameplay_bootstrap_topic() {
98:afb|        let config = game_logic::network::network_manager_config();
99:78f|        assert_eq!(
100:cb8|            config.bootstrap_topics,
101:62f|            vec![game_logic::network::GLOBAL_GAMEPLAY_TOPIC_ID.to_string()]
102:82c|        );
103:b18|    }
104:b18|}

